import subprocess

def get_latest_commit_message():
    """Fetches the latest commit message from the pytorch/pytorch main branch."""
    try:
        result = subprocess.run(
            ["git", "log", "-1", "--pretty=%B", "origin/main"],
            capture_output=True,
            text=True,
            check=True
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError as e:
        print(f"Error fetching commit message: {e}")
        return None

if __name__ == "__main__":
    commit_message = get_latest_commit_message()
    if commit_message:
        print("Latest commit message on pytorch/pytorch main branch:")
        print(commit_message)

